import math
import random

def accept_token(p_token, q_token):
    ratio = p_token / max(q_token, 1e-12)  # 用 p/q 衡量 target 是否同意 draft 的自信度
    accept_prob = min(1.0, ratio)  # 接受率大于 1 没意义，所以截断到 1
    return random.random() < accept_prob  # 只有被接受的草稿 token 才能跳过一次 target 单步生成

def accepted_count(p_list, q_list):
    count = 0
    for p_token, q_token in zip(p_list, q_list):
        if accept_token(p_token, q_token):
            count += 1  # 每多接受一个 token，就少一次串行等待
        else:
            break  # 一旦拒绝，就要回到 target 分布重新采样
    return count
